import React from 'react';
import MenuLateral from '../components/MenuLateral';
import AcompanhamentoInfra from '../components/AcompanhamentoInfra';
import { useNavigate } from 'react-router-dom';

export default function PaginaAcompanhamentoInfra(props) {
  // Busca clienteSelecionado do localStorage
  let razaoSocial = '';
  let cnpj = '';
  try {
    const salvo = localStorage.getItem('clienteSelecionado');
    if (salvo) {
      const obj = JSON.parse(salvo);
      razaoSocial = obj.razaoSocial || '';
      cnpj = obj.cnpj || '';
    }
  } catch {}

  const navigate = useNavigate();

  return (
    <div style={{ display: 'flex' }}>
      <MenuLateral
        voltarLink={<span style={{cursor:'pointer',color:'#fff',fontSize:22}} onClick={() => navigate(-1)} title="Voltar">←</span>}
        clienteInfo={
          <>
            <div style={{fontWeight:700, fontSize: '1.1rem', color: '#fff'}}>{razaoSocial}</div>
            <div style={{fontWeight:500, fontSize: '0.95rem', color: '#fff'}}>CNPJ: {cnpj}</div>
          </>
        }
      />
      <div style={{ marginLeft: 220, width: '100%' }}>
        <AcompanhamentoInfra {...props} razaoSocial={razaoSocial} />
      </div>
    </div>
  );
}
